        window.translations = translations;
        // ── Translation System Functions ───────────────────────────
        // FIX: Додано відсутні функції після запуску add-polish.py

        // Поточна мова (дефолт: українська)
        window.currentLanguage = localStorage.getItem('talko_language') || 'ua';
        // FIX: alias для зворотної сумісності — деякі модулі використовують currentLang без window.
        window.currentLang = window.currentLanguage;

        // Функція перекладу
        window.t = function(key) {
            if (!key) return '';
            const lang = window.currentLanguage || 'ua';
            const translations = window.translations || {};
            const langPack = translations[lang] || {};
            // FIX: якщо ключ відсутній в обраній мові → fallback на UA (не на сам key)
            // Це виправляє часткові переклади (RU має ~50% ключів)
            return langPack[key] || translations['ua']?.[key] || key;
        };

        // Зміна мови
        // ── Apply data-i18n translations to DOM ──────────────────
        window.applyNavTranslations = function(lang) {
            const t = window.t;
            if (!t) return;
            // Apply to all [data-i18n] elements
            document.querySelectorAll('[data-i18n]').forEach(function(el) {
                const key = el.getAttribute('data-i18n');
                const val = t(key);
                if (val && val !== key) {
                    // Якщо значення містить HTML теги — використовуємо innerHTML
                    // (наприклад signIn містить <i data-lucide=...>)
                    if (val.includes('<') && val.includes('>')) {
                        el.innerHTML = val;
                    } else {
                        el.textContent = val;
                    }
                }
            });
            // Apply to [data-i18n-placeholder]
            document.querySelectorAll('[data-i18n-placeholder]').forEach(function(el) {
                const key = el.getAttribute('data-i18n-placeholder');
                const val = t(key);
                if (val && val !== key) el.placeholder = val;
            });
            // Apply to [data-i18n-title]
            document.querySelectorAll('[data-i18n-title]').forEach(function(el) {
                const key = el.getAttribute('data-i18n-title');
                const val = t(key);
                if (val && val !== key) el.title = val;
            });
        };

        // Auto-apply on load if language is not UA
        (function() {
            const lang = window.currentLanguage || 'ua';
            if (lang !== 'ua') {
                document.addEventListener('DOMContentLoaded', function() {
                    window.applyNavTranslations(lang);
                });
                // Also apply after a short delay for dynamic content
                setTimeout(function() {
                    if (typeof window.applyNavTranslations === 'function') {
                        window.applyNavTranslations(lang);
                    }
                }, 300);
                setTimeout(function() {
                    if (typeof window.applyNavTranslations === 'function') {
                        window.applyNavTranslations(lang);
                    }
                }, 1500);
            }
        })();


        window.setLanguage = function(lang, forceReload) {
            if (!lang || !window.translations[lang]) return;
            // FIX CRITICAL: reload тільки якщо мова реально змінилась
            // Раніше — reload при кожному виклику включно з ініціалізацією → нескінченний loop
            const prevLang = window.currentLanguage;
            window.currentLanguage = lang;
            window.currentLang = lang; // keep alias in sync
            localStorage.setItem('talko_language', lang);

            // Зберігаємо мову в Firestore — щоб Telegram сповіщення теж перекладались
            try {
                if (window.currentUser && window.currentCompany && typeof db !== 'undefined') {
                    db.collection('companies').doc(window.currentCompany)
                        .collection('users').doc(window.currentUser.uid)
                        .update({ language: lang })
                        .catch(function(e) { console.warn('[i18n] Failed to save language to Firestore:', e.message); });
                }
            } catch(e) { /* silent */ }

            // Оновлюємо весь UI без reload
            if (typeof updatePageTranslations === 'function') {
                updatePageTranslations();
            }

            // FIX: на auth сторінці — НЕ робимо reload (Firebase не встиг відновити сесію)
            // FIX: auth сторінка = currentUser відсутній АБО authScreen видимий
            const _authEl = document.getElementById('authPage');
            const _authVisible = _authEl && _authEl.style.display !== 'none' && _authEl.offsetParent !== null;
            const _isAuthPage = !window.currentUser || _authVisible;
            if (_isAuthPage) {
                if (typeof window.applyNavTranslations === 'function') window.applyNavTranslations(lang);
                return;
            }
            // Для залогіненого юзера — reload щоб оновити весь UI
            if (forceReload === true || (prevLang && prevLang !== lang)) {
                location.reload();
            }
        };

        // Отримання локалі для Date формату
        window.getLocale = function() {
            const lang = window.currentLanguage || 'ua';
            const localeMap = {
                'ua': 'uk-UA',
                'en': 'en-US',
                'de': 'de-DE',
                'cs': 'cs-CZ',
                'ru': 'ru-RU',
                'pl': 'pl-PL'
            };
            return localeMap[lang] || 'uk-UA';
        };
